#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        int *c = (int*)malloc(N*sizeof(int));
        long long *w = (long long*)malloc(N*sizeof(long long));
        for(int i=0;i<N;++i) scanf("%d",&c[i]);
        for(int i=0;i<N;++i) scanf("%lld",&w[i]);
        int *last = (int*)malloc(N*sizeof(int));
        for(int i=0;i<N;++i) last[i] = -1;
        int left = 0; long long cur = 0, best = 0;
        for(int right=0; right<N; ++right){
            int col = c[right];
            if(last[col] >= left){
                while(left <= last[col]){ cur -= w[left]; ++left; }
            }
            cur += w[right];
            if(cur > best) best = cur;
            last[col] = right;
        }
        printf("%lld\n",best);
        free(c); free(w); free(last);
    }
    return 0;
}

